import sailpoint.object.*;
import java.util.*;

/**
 * ISDS Set Account DN
 *
 * Generates the LDAP Distinguished Name (DN) for ISDS provisioning.
 *
 * Identity type mapping:
 *   - partner  -> uid=<itauloginebusiness>,cn=users,dc=rc,dc=itau
 *   - service  -> uid=<identityName>,cn=SvcAccounts,dc=rc,dc=itau
 *                 NOTE: uniqueness for service accounts is enforced via
 *                 cloudMaxUniqueChecks in the provisioning policy field.
 *                 This differs from the IIQ implementation which queried
 *                 Link objects directly (context.countObjects).
 *   - default  -> uid=<itaufuncional>,cn=users,dc=rc,dc=itau
 *
 * Migrated from IIQ Rule: ISDS Set Account DN (id: 0a3afd6673ed168a8173ed19c08e002b)
 */
try {
    String idtyType = identity.getAttribute("identityType");
    String acctDN = null;

    if (idtyType == null || idtyType.trim().isEmpty()) {
        idtyType = "default";
    }

    if ("partner".equalsIgnoreCase(idtyType)) {
        String loginEbusiness = identity.getAttribute("itauloginebusiness");
        if (loginEbusiness != null && !loginEbusiness.trim().isEmpty()) {
            acctDN = "uid=" + loginEbusiness.trim() + ",cn=users,dc=rc,dc=itau";
        } else {
            log.warn("ISDS Set Account DN: identity type is 'partner' but 'itauloginebusiness' attribute is null or empty. Identity: " + identity.getName());
        }

    } else if ("service".equalsIgnoreCase(idtyType)) {
        /*
         * Service accounts use cn=SvcAccounts.
         * Uniqueness is handled by cloudMaxUniqueChecks (set to 100) in the
         * provisioning policy field, matching the IIQ loop limit of 100 tries.
         * The ISC engine appends a numeric counter when a collision is detected.
         */
        String identityName = identity.getName();
        if (identityName != null && !identityName.trim().isEmpty()) {
            acctDN = "uid=" + identityName.trim() + ",cn=SvcAccounts,dc=rc,dc=itau";
        } else {
            log.warn("ISDS Set Account DN: identity type is 'service' but identity name is null or empty.");
        }

    } else {
        // default: regular employees and all other types
        String itaufuncional = identity.getAttribute("itaufuncional");
        if (itaufuncional != null && !itaufuncional.trim().isEmpty()) {
            acctDN = "uid=" + itaufuncional.trim() + ",cn=users,dc=rc,dc=itau";
        } else {
            log.warn("ISDS Set Account DN: 'itaufuncional' attribute is null or empty. Identity: " + identity.getName() + ", type: " + idtyType);
        }
    }

    return acctDN;

} catch (Exception e) {
    log.error("ISDS Set Account DN: unexpected error generating DN for identity: " + identity.getName(), e);
    return null;
}
